registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLen: 48,
    prevX: g.px,
    prevY: g.py
  };

  var t = g._trail;
  var ctx = g.ctx;
  var moved = (Math.abs(g.px - t.prevX) > 0.01 || Math.abs(g.py - t.prevY) > 0.01);

  if (moved) {
    t.points.push({ x: t.prevX, y: t.prevY, age: 0 });
    if (t.points.length > t.maxLen) {
      t.points.shift();
    }
  }

  t.prevX = g.px;
  t.prevY = g.py;

  var len = t.points.length;
  if (len < 2) return;

  // Draw trail as connected segments with fading color and width
  for (var i = 1; i < len; i++) {
    var p0 = t.points[i - 1];
    var p1 = t.points[i];
    var progress = i / len; // 0 = oldest, 1 = newest

    var alpha = progress * progress * 0.85;
    var width = progress * 3.5;

    // Color shifts from cyan-blue (old) to bright green (new)
    var r = Math.round(g.lerp(0, 0, progress));
    var gr = Math.round(g.lerp(180, 255, progress));
    var b = Math.round(g.lerp(220, 100, progress));

    ctx.beginPath();
    ctx.moveTo(p0.x, p0.y);
    ctx.lineTo(p1.x, p1.y);
    ctx.strokeStyle = 'rgba(' + r + ',' + gr + ',' + b + ',' + alpha + ')';
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();
  }

  // Glow pulse at tail origin (oldest visible point)
  var tail = t.points[0];
  var glowAlpha = 0.10 + 0.05 * Math.sin(g.tick * 0.18);
  ctx.beginPath();
  ctx.arc(tail.x, tail.y, 4, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(0,180,220,' + glowAlpha + ')';
  ctx.fill();

  // Bright spark dot at the head to merge into the player pixel
  var head = t.points[len - 1];
  ctx.beginPath();
  ctx.arc(head.x, head.y, 2.2, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(0,255,170,0.55)';
  ctx.fill();
})

registerModule('Ambient Starfield', function(g) {
  g._starfield = g._starfield || (function() {
    var stars = [];
    var count = 180;
    for (var i = 0; i < count; i++) {
      stars.push({
        x: Math.random() * 800,
        y: Math.random() * 600,
        r: Math.random() * 1.6 + 0.2,
        speed: Math.random() * 0.18 + 0.04,
        twinkle: Math.random() * Math.PI * 2,
        twinkleSpeed: Math.random() * 0.04 + 0.008,
        hue: Math.random() < 0.15 ? (Math.random() * 60 + 180) : 0,
        sat: Math.random() < 0.15 ? 80 : 0,
        drift: (Math.random() - 0.5) * 0.012
      });
    }
    return { stars: stars, initialized: false };
  }());

  var state = g._starfield;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Parallax offset based on player position
  var cx = g.canvas.width * 0.5;
  var cy = g.canvas.height * 0.5;
  var parallaxX = (g.px - cx) * 0.012;
  var parallaxY = (g.py - cy) * 0.012;

  var stars = state.stars;
  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Drift slowly downward and sideways
    s.y += s.speed;
    s.x += s.drift;
    s.twinkle += s.twinkleSpeed;

    // Wrap around canvas edges
    if (s.y > H + 2) { s.y = -2; s.x = Math.random() * W; }
    if (s.x < -2)    { s.x = W + 2; }
    if (s.x > W + 2) { s.x = -2; }

    // Twinkle: oscillate alpha
    var alpha = 0.35 + 0.55 * (0.5 + 0.5 * Math.sin(s.twinkle));

    // Parallax shift
    var drawX = s.x - parallaxX * s.speed * 6;
    var drawY = s.y - parallaxY * s.speed * 6;

    // Color: mostly white/blue-white, occasional tinted
    var color;
    if (s.hue !== 0) {
      color = 'hsla(' + s.hue + ',' + s.sat + '%,88%,' + alpha.toFixed(2) + ')';
    } else {
      color = 'rgba(200,220,255,' + alpha.toFixed(2) + ')';
    }

    ctx.beginPath();
    ctx.arc(drawX, drawY, s.r, 0, 6.2832);
    ctx.fillStyle = color;
    ctx.fill();

    // Subtle glow for larger stars
    if (s.r > 1.2) {
      ctx.beginPath();
      ctx.arc(drawX, drawY, s.r * 2.8, 0, 6.2832);
      var glowAlpha = alpha * 0.18;
      if (s.hue !== 0) {
        ctx.fillStyle = 'hsla(' + s.hue + ',' + s.sat + '%,88%,' + glowAlpha.toFixed(3) + ')';
      } else {
        ctx.fillStyle = 'rgba(180,210,255,' + glowAlpha.toFixed(3) + ')';
      }
      ctx.fill();
    }
  }
})
